📝 C-Code (POSIX Threads)☕ Java-Code (Java Threads)🐍 Python-Code (Threading Modul) <pre><code>#include &lt;pthread.h&gt; 
#include &lt;stdio.h&gt; 
void* thread_function(void* arg) { 
    printf("Hello from thread!\\n"); return NULL; 
} 
int main() { 
    pthread_t thread; pthread_create(&amp;thread, NULL, thread_function, NULL);
    pthread_join(thread, NULL); return 0; 
}
</code></pre> <pre><code>class MyThread extends Thread {
    public void run() {
        System.out.println("Hello from thread!");
    }
}

public class Main { 
    public static void main(String[] args) { 
        MyThread t = new MyThread(); t.start(); 
    } 
}
</code></pre> <pre><code>import threading

def thread_function():
    print("Hello from thread!")

thread = threading.Thread(target=thread_function)
thread.start()
thread.join()
</code></pre>

📝 C-Code mit Mutex☕ Java mit Synchronized🐍 Python mit Lock <pre><code>void* increment(void* arg) {
    for (int i = 0; i &lt; 100000; i++) {
        pthread_mutex_lock(&amp;lock);
        counter++;
        pthread_mutex_unlock(&amp;lock);
    }
}
</code></pre> <pre><code>java class Counter { 
    private int count = 0;

    public synchronized void increment() { 
        count++; 
    } 
}
</code></pre> <pre><code>counter = 0
lock = threading.Lock()

def increment():
    global counter
    with lock:
        counter += 1
</code></pre>

